const params = $input.first().json.query || {};
const month = params.month ? Number(params.month) : null;
const year = params.year ? Number(params.year) : null;

const cols = `cr.id, cr.profile_name, cr.start_date, cr.end_date,
  cr.search_views, cr.interactions, cr.website_clicks, cr.direction_requests,
  cr.phone_calls, cr.reviews, cr.review_responses, cr.ratings,
  cr.website_speed, cr.seo_score, cr.primary_keyword, cr.primary_rank,
  cr.keyword_1, cr.rank_1, cr.keyword_2, cr.rank_2,
  cr.keyword_3, cr.rank_3, cr.keyword_4, cr.rank_4,
  cr.keyword_5, cr.rank_5, cr.citations, cr.backlinks,
  cr.content_marketing, cr.creatives, cr.shorts_reels, cr.medical_blogs,
  cr.website_seo, cr.local_seo, cr.web_social_audit, cr.google_profile_rank,
  c.client_name, c.specialisation, c.location, c.city_name,
  c.website_url, c.gmb_profile_link, c.fb_page_link, c.instagram_link, c.youtube_link`;

let query;
if (month && year) {
  query = `SELECT ${cols}
FROM dr_smart.client_reports cr
LEFT JOIN dr_smart.clients c ON LOWER(TRIM(c.client_name)) = LOWER(TRIM(cr.profile_name))
WHERE EXTRACT(MONTH FROM cr.start_date) = ${month}
  AND EXTRACT(YEAR FROM cr.start_date) = ${year}
ORDER BY cr.profile_name;`;
} else {
  query = `SELECT ${cols}
FROM dr_smart.client_reports cr
LEFT JOIN dr_smart.clients c ON LOWER(TRIM(c.client_name)) = LOWER(TRIM(cr.profile_name))
ORDER BY cr.profile_name;`;
}

return [{ json: { query } }];

const brands = $input.all().map(item => {
  const d = item.json;

  const keywords = [];
  for (let i = 1; i <= 5; i++) {
    const kw = d[`keyword_${i}`];
    const rk = d[`rank_${i}`];
    if (kw && kw.trim()) {
      keywords.push({ keyword: kw.trim(), rank: Number(rk) || 0 });
    }
  }

  return {
    name: d.profile_name || d.client_name || '',
    startDate: d.start_date,
    endDate: d.end_date,
    searchViews: Number(d.search_views) || 0,
    interactions: Number(d.interactions) || 0,
    websiteClicks: Number(d.website_clicks) || 0,
    directionRequests: Number(d.direction_requests) || 0,
    phoneCalls: Number(d.phone_calls) || 0,
    reviews: Number(d.reviews) || 0,
    reviewResponses: Number(d.review_responses) || 0,
    ratings: Number(d.ratings) || 0,
    websiteSpeed: Number(d.website_speed) || 0,
    seoScore: Number(d.seo_score) || 0,
    primaryKeyword: d.primary_keyword || '',
    primaryRank: Number(d.primary_rank) || 0,
    keywords,
    citations: Number(d.citations) || 0,
    backlinks: Number(d.backlinks) || 0,
    contentMarketing: Number(d.content_marketing) || 0,
    creatives: Number(d.creatives) || 0,
    shortsReels: Number(d.shorts_reels) || 0,
    medicalBlogs: Number(d.medical_blogs) || 0,
    websiteSEO: Boolean(d.website_seo),
    localSEO: Boolean(d.local_seo),
    webSocialAudit: Boolean(d.web_social_audit),
    googleProfileRank: Number(d.google_profile_rank) || 0,
    specialty: d.specialisation || '',
    location: d.city_name || d.location || '',
    websiteUrl: d.website_url || '',
    gmbProfileLink: d.gmb_profile_link || '',
    fbPageLink: d.fb_page_link || '',
    instagramLink: d.instagram_link || '',
    youtubeLink: d.youtube_link || ''
  };
});

return [{ json: { brands } }];

const body = $input.first().json.body;

if (!body.name) {
  throw new Error('name is required for deletion');
}

const safeName = body.name.trim().replace(/'/g, "''");
const query = `DELETE FROM dr_smart.clients WHERE client_name = '${safeName}';`;

return [{ json: { query } }];

