const dates = $('Fetch Only Dates With Records').all().map(item => item.json.available_date);
const records = $('Fetch Absolute Latest Records').all().map(item => item.json);

return [{
  json: {
    availableDates: dates,
    currentRecords: records
  }
}];

const records = $('Fetch Selected Date Records').all().map(item => item.json);

return [{
  json: {
    currentRecords: records
  }
}];

return $input.all().map(item => {
  const row = item.json;

  // 1. Safely handle JSONB fields
  // Sometimes the Postgres driver returns JSONB as a string, sometimes as an object. This handles both.
  let parsedBusinessInfo = {};
  let parsedRankings = [];

  try {
    parsedBusinessInfo = typeof row.business_info === 'string' 
      ? JSON.parse(row.business_info) 
      : (row.business_info || {});
  } catch (e) {
    parsedBusinessInfo = {};
  }

  try {
    parsedRankings = typeof row.rankings === 'string' 
      ? JSON.parse(row.rankings) 
      : (row.rankings || []);
  } catch (e) {
    parsedRankings = [];
  }

  // 2. Format and return clean data for your frontend
  return {
    json: {
      placeId: row.place_id,
      businessName: row.business_name,

      // Flattening the nested business info so your frontend code is cleaner
      category: parsedBusinessInfo.category || "N/A",
      rating: parsedBusinessInfo.rating || null,
      reviews: parsedBusinessInfo.reviews || 0,
      address: parsedBusinessInfo.address || "N/A",
      phone: parsedBusinessInfo.phone || "N/A",
      mapsUrl: parsedBusinessInfo.maps_url || null,

      // The clean array of { keyword, rank }
      rankings: parsedRankings,
      scrapedAt: row.created_at
    }
  };
});

const total_credits = $input.first().json.data.total_credits;
const total_usage = $input.first().json.data.total_usage;
const current_balance = total_credits - total_usage;

return [{ json: { current_balance } }];
